// Pull both ensures-foralls into the proof context so their triggers fire
// on the shared `v`.
assert(forall|v: T| #![auto] post1_self_@.contains(v) ==>
    pre_self_.get_node_ref(v) == post1_self_.get_node_ref(v));
assert(forall|v: T| #![auto] post2_self_@.contains(v) ==>
    pre_self_.get_node_ref(v) == post2_self_.get_node_ref(v));

// Both post-views equal pre_self_@.skip(1); close with Seq extensionality.
assert(post1_self_@ =~= post2_self_@);

// First component: both equal pre_self_@[0].
assert(r1.0 == r2.0);

// Second component: r.1 == pre_self_.get_node_ref(r.0), and r1.0 == r2.0,
// so congruence on pre_self_.get_node_ref forces r1.1 == r2.1.
assert(r1.1 == r2.1);

// Pointwise get_node_ref agreement on shared elements, going both ways so
// the determinism predicate has the equality regardless of which side it
// quantifies over.
assert forall|v: T| post1_self_@.contains(v) implies
    post1_self_.get_node_ref(v) == post2_self_.get_node_ref(v) by {
    assert(post2_self_@.contains(v));
}
assert forall|v: T| post2_self_@.contains(v) implies
    post1_self_.get_node_ref(v) == post2_self_.get_node_ref(v) by {
    assert(post1_self_@.contains(v));
}
